using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServerDemo;

[McpServerToolType]
public sealed class WeatherTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    public WeatherTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool(Name = "get_weather")]
    [Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetWeatherAsync(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        var client = _httpClientFactory.CreateClient("WeatherApi");

        var response = await client.GetAsync(
            $"v1/forecast?latitude={latitude}&longitude={longitude}&current_weather=true");

        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>();
        var weather = json.GetProperty("current_weather");

        return $"Temperature: {weather.GetProperty("temperature")}°C, " +
               $"Wind: {weather.GetProperty("windspeed")} km/h, " +
               $"Code: {weather.GetProperty("weathercode")}";
    }

    [McpServerTool(Name = "get_forecast")]
    [Description("Get a 7-day temperature forecast for a location.")]
    public async Task<string> GetForecastAsync(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        var client = _httpClientFactory.CreateClient("WeatherApi");

        var response = await client.GetAsync(
            $"v1/forecast?latitude={latitude}&longitude={longitude}" +
            "&daily=temperature_2m_max,temperature_2m_min&timezone=auto");

        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>();
        var daily = json.GetProperty("daily");
        var dates = daily.GetProperty("time").EnumerateArray().ToList();
        var maxTemps = daily.GetProperty("temperature_2m_max").EnumerateArray().ToList();
        var minTemps = daily.GetProperty("temperature_2m_min").EnumerateArray().ToList();

        var lines = dates.Select((d, i) =>
            $"{d.GetString()}: {minTemps[i]}°C - {maxTemps[i]}°C");

        return string.Join("\n", lines);
    }
}

